public class Solution {
    final static int MOD = 1000000007;

    public static int corridorWays(String corridor) {
        int n = corridor.length();
        int[] dp = new int[n + 1];
        dp[0] = 1;

        int seats = 0;
        for (int i = 0; i < n; i++) {
            if (corridor.charAt(i) == 'S') {
                seats++;
                if (seats % 2 == 0) {
                    dp[i + 1] = dp[Math.max(0, i - 1)];
                }
                dp[i + 1] = (dp[i] + dp[i + 1]) % MOD;
            } else {
                dp[i + 1] = dp[i];
            }
        }

        return dp[n];
    }
}
```

